DROP VIEW "public"."v_transactions_effective";--> statement-breakpoint
CREATE VIEW "public"."v_transactions_effective" AS (select "transactions"."id", "transactions"."account_id", "transactions"."item_id", "transactions"."plaid_transaction_id", "transactions"."amount", "transactions"."iso_currency_code", "transactions"."date", "transactions"."name", "transactions"."merchant_name", coalesce("transactions"."user_category_id", "transactions"."category_id") as "effective_category_id", "categories"."slug" as "category_slug", "categories"."name" as "category_name", "transactions"."pending" from "transactions" left join "categories" on "categories"."id" = coalesce("transactions"."user_category_id", "transactions"."category_id") where "transactions"."removed_at" is null and "transactions"."is_hidden" = false);